const { withAndroidManifest, withDangerousMod, AndroidConfig } = require("expo/config-plugins");
const fs = require("fs");
const path = require("path");

/**
 * Injects the home-screen widget into the Android project during prebuild. The native
 * dirs are gitignored and regenerated by `expo prebuild`, so the canonical widget
 * sources live in the tracked `widget/android/` tree and are copied in here:
 *   - res/ (layouts, drawable, xml, generated widget_theme.xml + values-night) → app res
 *   - java/ Kotlin, with __PKG__ templated to the resolved variant package, written
 *     under the matching package path
 *   - an AppWidgetProvider <receiver> added to the manifest
 *
 * The package differs by variant (com.veloq.app vs com.veloq.app.dev, see app.config.js),
 * which is why the Kotlin uses a __PKG__ placeholder rather than a hardcoded package.
 */

const RECEIVER_NAME = ".widget.VeloqWidgetProvider";

function copyDir(src, dest) {
  fs.mkdirSync(dest, { recursive: true });
  for (const entry of fs.readdirSync(src, { withFileTypes: true })) {
    const from = path.join(src, entry.name);
    const to = path.join(dest, entry.name);
    if (entry.isDirectory()) {
      copyDir(from, to);
    } else {
      fs.copyFileSync(from, to);
    }
  }
}

function withWidgetSources(config) {
  return withDangerousMod(config, [
    "android",
    (cfg) => {
      const androidRoot = cfg.modRequest.platformProjectRoot;
      const widgetSrc = path.join(cfg.modRequest.projectRoot, "widget", "android");
      const pkg = cfg.android?.package || "com.veloq.app";
      const mainSrc = path.join(androidRoot, "app", "src", "main");

      copyDir(path.join(widgetSrc, "res"), path.join(mainSrc, "res"));

      const javaDest = path.join(mainSrc, "java", pkg.replace(/\./g, "/"), "widget");
      fs.mkdirSync(javaDest, { recursive: true });
      const javaSrc = path.join(widgetSrc, "java");
      for (const file of fs.readdirSync(javaSrc)) {
        const templated = fs.readFileSync(path.join(javaSrc, file), "utf8").replace(/__PKG__/g, pkg);
        fs.writeFileSync(path.join(javaDest, file), templated);
      }
      return cfg;
    },
  ]);
}

function withWidgetReceiver(config) {
  return withAndroidManifest(config, (mod) => {
    const app = AndroidConfig.Manifest.getMainApplicationOrThrow(mod.modResults);
    app.receiver = app.receiver || [];
    const exists = app.receiver.some((r) => r.$?.["android:name"] === RECEIVER_NAME);
    if (!exists) {
      app.receiver.push({
        $: { "android:name": RECEIVER_NAME, "android:exported": "true" },
        "intent-filter": [
          {
            action: [{ $: { "android:name": "android.appwidget.action.APPWIDGET_UPDATE" } }],
          },
        ],
        "meta-data": [
          {
            $: {
              "android:name": "android.appwidget.provider",
              "android:resource": "@xml/veloq_widget_info",
            },
          },
        ],
      });
    }
    return mod;
  });
}

module.exports = function withAndroidWidget(config) {
  config = withWidgetReceiver(config);
  config = withWidgetSources(config);
  return config;
};
